import{_ as n,c as a,o as e,ag as t}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"Agent CLI — Assembly Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-cli/docs/ASSEMBLY-ARCHITECTURE.md","filePath":"packages/agent-cli/docs/ASSEMBLY-ARCHITECTURE.md"}'),o={name:"packages/agent-cli/docs/ASSEMBLY-ARCHITECTURE.md"};function i(l,s,p,r,c,d){return e(),a("div",null,s[0]||(s[0]=[t(`<h1 id="agent-cli-—-assembly-architecture" tabindex="-1">Agent CLI — Assembly Architecture <a class="header-anchor" href="#agent-cli-—-assembly-architecture" aria-label="Permalink to &quot;Agent CLI — Assembly Architecture&quot;">​</a></h1><p>How <code>@robota-sdk/agent-cli</code> is composed from lower-level packages.</p><h2 id="dependency-graph" tabindex="-1">Dependency Graph <a class="header-anchor" href="#dependency-graph" aria-label="Permalink to &quot;Dependency Graph&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      agent-cli                               │</span></span>
<span class="line"><span>│  Terminal UI (React + Ink), slash commands, permission UX     │</span></span>
<span class="line"><span>│  Assembles: createSession() → FileSessionLogger → render()   │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────┬────────────────────┘</span></span>
<span class="line"><span>               │                          │</span></span>
<span class="line"><span>               ▼                          ▼</span></span>
<span class="line"><span>┌──────────────────────────┐   ┌──────────────────────┐</span></span>
<span class="line"><span>│        agent-sdk         │   │     agent-core       │</span></span>
<span class="line"><span>│  Assembly layer:         │   │  (direct dep for     │</span></span>
<span class="line"><span>│  createSession(),        │   │   type imports only)  │</span></span>
<span class="line"><span>│  createDefaultTools(),   │   └──────────────────────┘</span></span>
<span class="line"><span>│  createProvider(),       │</span></span>
<span class="line"><span>│  config, context,        │</span></span>
<span class="line"><span>│  system prompt builder   │</span></span>
<span class="line"><span>└──────────┬───────────────┘</span></span>
<span class="line"><span>           │ composes</span></span>
<span class="line"><span>     ┌─────┼──────────┬─────────────────┐</span></span>
<span class="line"><span>     ▼     ▼          ▼                 ▼</span></span>
<span class="line"><span>┌─────────┐ ┌────────────┐ ┌───────────────────────┐ ┌──────────┐</span></span>
<span class="line"><span>│ agent-  │ │  agent-    │ │ agent-provider-       │ │ agent-   │</span></span>
<span class="line"><span>│sessions │ │  tools     │ │ anthropic             │ │  core    │</span></span>
<span class="line"><span>│         │ │            │ │                       │ │          │</span></span>
<span class="line"><span>│ Session │ │ Bash, Read │ │ AnthropicProvider     │ │ Robota   │</span></span>
<span class="line"><span>│ Logger  │ │ Write,Edit │ │ (Anthropic SDK)       │ │ Plugins  │</span></span>
<span class="line"><span>│ Store   │ │ Glob, Grep │ │ Streaming             │ │ Events   │</span></span>
<span class="line"><span>│Enforcer │ │ WebFetch   │ │ Server tools          │ │ DI       │</span></span>
<span class="line"><span>│Tracker  │ │ WebSearch  │ │                       │ │          │</span></span>
<span class="line"><span>│Compactor│ │            │ │                       │ │          │</span></span>
<span class="line"><span>└────┬────┘ └─────┬──────┘ └───────────┬───────────┘ └────┬─────┘</span></span>
<span class="line"><span>     │            │                    │                   │</span></span>
<span class="line"><span>     └────────────┴────────────────────┴───────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>                    ┌──────────────┐</span></span>
<span class="line"><span>                    │  agent-core  │</span></span>
<span class="line"><span>                    │              │</span></span>
<span class="line"><span>                    │ Interfaces   │</span></span>
<span class="line"><span>                    │ Abstractions │</span></span>
<span class="line"><span>                    │ Plugin system│</span></span>
<span class="line"><span>                    │ Event service│</span></span>
<span class="line"><span>                    │ Tool registry│</span></span>
<span class="line"><span>                    │ Permissions  │</span></span>
<span class="line"><span>                    │ Hooks        │</span></span>
<span class="line"><span>                    └──────────────┘</span></span></code></pre></div><p><strong>Key change:</strong> <code>agent-sessions</code> now depends only on <code>agent-core</code>. Tools and provider dependencies moved to <code>agent-sdk</code> (assembly layer).</p><h2 id="layer-responsibilities" tabindex="-1">Layer Responsibilities <a class="header-anchor" href="#layer-responsibilities" aria-label="Permalink to &quot;Layer Responsibilities&quot;">​</a></h2><h3 id="layer-0-agent-core-foundation" tabindex="-1">Layer 0: agent-core (Foundation) <a class="header-anchor" href="#layer-0-agent-core-foundation" aria-label="Permalink to &quot;Layer 0: agent-core (Foundation)&quot;">​</a></h3><ul><li><strong>Owns:</strong> Interfaces, abstractions, DI, event service, plugin system, tool registry, permissions, hooks</li><li><strong>Dependencies:</strong> Zero @robota-sdk dependencies</li><li><strong>Rule:</strong> Everything above depends on core. Core depends on nothing.</li></ul><h3 id="layer-1-implementation-packages-building-blocks" tabindex="-1">Layer 1: Implementation Packages (Building Blocks) <a class="header-anchor" href="#layer-1-implementation-packages-building-blocks" aria-label="Permalink to &quot;Layer 1: Implementation Packages (Building Blocks)&quot;">​</a></h3><ul><li><strong>agent-tools</strong> — Built-in tool implementations (Bash, Read, Write, Edit, Glob, Grep, WebFetch, WebSearch). Depends on core for <code>IToolWithEventService</code>.</li><li><strong>agent-provider-anthropic</strong> — Anthropic AI provider (chat, streaming, server tools). Depends on core for <code>IAIProvider</code>.</li><li><strong>agent-sessions</strong> — Generic session lifecycle (Session, PermissionEnforcer, ContextWindowTracker, CompactionOrchestrator, SessionStore). Depends on core only. Accepts tools and provider as constructor arguments.</li></ul><h3 id="layer-2-agent-sdk-assembly" tabindex="-1">Layer 2: agent-sdk (Assembly) <a class="header-anchor" href="#layer-2-agent-sdk-assembly" aria-label="Permalink to &quot;Layer 2: agent-sdk (Assembly)&quot;">​</a></h3><ul><li><strong>Assembles</strong> tools + provider + system prompt → Session via <code>createSession()</code></li><li><strong>Factories:</strong> <code>createDefaultTools()</code>, <code>createProvider()</code>, <code>createSession()</code></li><li><strong>Adds</strong> config loading, context loading, system prompt building</li><li><strong>Exports</strong> assembly functions + backward-compatible re-exports</li><li><strong>Rule:</strong> SDK is the composition layer. It wires building blocks but adds minimal logic.</li></ul><h3 id="layer-3-agent-cli-ui" tabindex="-1">Layer 3: agent-cli (UI) <a class="header-anchor" href="#layer-3-agent-cli-ui" aria-label="Permalink to &quot;Layer 3: agent-cli (UI)&quot;">​</a></h3><ul><li><strong>Consumes</strong> SDK public API (primarily <code>createSession()</code>)</li><li><strong>Adds</strong> React + Ink terminal UI, slash commands, permission prompt UX, streaming display</li><li><strong>Assembles at startup:</strong> Creates <code>FileSessionLogger</code>, <code>SessionStore</code>, calls <code>createSession()</code>, renders UI</li><li><strong>Rule:</strong> CLI must not use core internals that should come through SDK/sessions.</li></ul><h2 id="assembly-flow-cli-startup" tabindex="-1">Assembly Flow (CLI Startup) <a class="header-anchor" href="#assembly-flow-cli-startup" aria-label="Permalink to &quot;Assembly Flow (CLI Startup)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. CLI parses args</span></span>
<span class="line"><span>2. CLI loads config + context         (via agent-sdk)</span></span>
<span class="line"><span>3. CLI creates FileSessionLogger      (from agent-sessions, via agent-sdk)</span></span>
<span class="line"><span>4. CLI creates SessionStore           (from agent-sessions, via agent-sdk)</span></span>
<span class="line"><span>5. CLI calls createSession({          (from agent-sdk assembly)</span></span>
<span class="line"><span>     config, context,</span></span>
<span class="line"><span>     sessionLogger,                   ← injected, not hardcoded</span></span>
<span class="line"><span>     sessionStore,                    ← injected, not hardcoded</span></span>
<span class="line"><span>     permissionHandler,               ← injected by CLI (React state callback)</span></span>
<span class="line"><span>     onTextDelta,                     ← injected by CLI (streaming display)</span></span>
<span class="line"><span>   })</span></span>
<span class="line"><span>6. createSession() internally:</span></span>
<span class="line"><span>   - Creates AnthropicProvider        (via createProvider)</span></span>
<span class="line"><span>   - Creates default tools            (via createDefaultTools)</span></span>
<span class="line"><span>   - Builds system prompt             (via buildSystemPrompt)</span></span>
<span class="line"><span>   - Passes all to new Session()      (generic Session, no hardcoded deps)</span></span>
<span class="line"><span>7. Session internally:</span></span>
<span class="line"><span>   - Wraps tools with PermissionEnforcer (using agent-core evaluatePermission)</span></span>
<span class="line"><span>   - Creates ContextWindowTracker</span></span>
<span class="line"><span>   - Creates CompactionOrchestrator</span></span>
<span class="line"><span>   - Creates Robota agent             (from agent-core)</span></span>
<span class="line"><span>8. CLI renders Ink TUI with Session</span></span></code></pre></div><h2 id="what-goes-where" tabindex="-1">What Goes Where <a class="header-anchor" href="#what-goes-where" aria-label="Permalink to &quot;What Goes Where&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Package</th><th>NOT in</th></tr></thead><tbody><tr><td>Terminal UI, React components</td><td>agent-cli</td><td>—</td></tr><tr><td>Config/context loading</td><td>agent-sdk</td><td>agent-cli</td></tr><tr><td>Session factory (assembly)</td><td>agent-sdk</td><td>agent-sessions</td></tr><tr><td>Tool + provider creation</td><td>agent-sdk</td><td>agent-sessions</td></tr><tr><td>System prompt building</td><td>agent-sdk</td><td>agent-sessions</td></tr><tr><td>Session lifecycle, permissions</td><td>agent-sessions</td><td>agent-sdk, agent-cli</td></tr><tr><td>Tool implementations</td><td>agent-tools</td><td>agent-sessions</td></tr><tr><td>AI provider calls</td><td>agent-provider-*</td><td>agent-sessions</td></tr><tr><td>Logging destination (file/DB)</td><td>ISessionLogger impl</td><td>Session class</td></tr><tr><td>Session persistence</td><td>SessionStore</td><td>Session class</td></tr><tr><td>Plugin system, events, DI</td><td>agent-core</td><td>anywhere else</td></tr><tr><td>Interfaces, type contracts</td><td>agent-core</td><td>duplicated elsewhere</td></tr></tbody></table>`,18)]))}const m=n(o,[["render",i]]);export{h as __pageData,m as default};
